 void render(){root=col(); root.setBackgroundColor(BG); root.setPadding(dp(14),dp(14),dp(14),0); root.addView(header()); if("map".equals(screen))root.addView(zoneTabs()); content=col(); root.addView(content,new LinearLayout.LayoutParams(-1,0,1)); if(!"staff".equals(screen))root.addView(addReservationBar(),full()); root.addView(nav()); if("res".equals(screen))resScreen(); else if("planner".equals(screen))planner(); else if("dash".equals(screen))dash(); else if("phone".equals(screen))phone(); else if("staff".equals(screen))staff(); else if("more".equals(screen))more(); else map(); setContentView(root);} 
