 void editPanel(){LinearLayout p=panel(); p.addView(txt("Bewerk plattegrond",22,INK,true)); p.addView(txt(selected.isEmpty()?"Tik een tafel aan. Sleep direct of gebruik de pijlen.":selected.size()+" tafel(s) geselecteerd",15,MUTED,false)); LinearLayout a=row(),b=row(),c=row(); a.addView(move("Omhoog",0,-2),w()); a.addView(move("Omlaag",0,2),w()); b.addView(move("Links",-2,0),w()); b.addView(move("Rechts",2,0),w()); c.addView(size("Groter",10),w()); c.addView(size("Kleiner",-10),w()); p.addView(a);p.addView(b);p.addView(c); LinearLayout d=row(); Button change=btn("Wijzig",Color.WHITE,BLACK); change.setOnClickListener(v->{Table t=first(); if(t==null)toast("Selecteer eerst een tafel"); else tableDialog(t,false);}); Button merge=btn("Samenvoegen",BLACK,Color.WHITE); merge.setOnClickListener(v->merge()); d.addView(change,w());d.addView(merge,w());p.addView(d); LinearLayout e=row(); Button split=btn("Losmaken",Color.WHITE,BLACK); split.setOnClickListener(v->{forSel(t->t.linked.clear());saveTables();render();}); Button del=btn("Verwijder",RED,Color.WHITE); del.setOnClickListener(v->deleteSelected()); e.addView(split,w());e.addView(del,w());p.addView(e); content.addView(p,full());}
 Button move(String s,int dx,int dy){Button b=btn(s,Color.WHITE,BLACK); b.setOnClickListener(v->{if(selected.isEmpty()){toast("Selecteer eerst een tafel");return;} forSel(t->{t.x=clamp(t.x+dx,4,96);t.y=clamp(t.y+dy,5,95);snap(t);}); saveTables(); render();}); return b;} Button size(String s,int d){Button b=btn(s,Color.WHITE,BLACK); b.setOnClickListener(v->{if(selected.isEmpty()){toast("Selecteer eerst een tafel");return;} forSel(t->{t.w=clamp(t.w+d,76,210);t.h=clamp(t.h+d,68,180);}); saveTables(); render();}); return b;}
 void planner(){ScrollView sv=new ScrollView(this); LinearLayout list=col(); sv.addView(list); LinearLayout top=panel(); top.addView(txt("Dagplanner",25,INK,true)); top.addView(riskView(dayAdvice("19:00",0,"Alles",""))); list.addView(top,full()); ArrayList<Res> rs=new ArrayList<>(reservations); Collections.sort(rs,(a,b)->a.time.compareTo(b.time)); for(Res r:rs){LinearLayout p=panel(); p.addView(txt(r.time+"  "+safe(r.name,"Gast"),20,INK,true)); p.addView(txt(r.party+"p - tafel "+(r.tables.isEmpty()?"geen":names(r.tables))+" - "+r.zone,15,MUTED,false)); if(special(r.notes))p.addView(txt("Let op: "+r.notes,16,RED,true)); else if(!r.notes.isEmpty())p.addView(txt("Notitie: "+r.notes,15,BLUE,true)); p.addView(riskView(dayAdvice(r.time,r.party,r.zone,r.notes))); list.addView(p,full());} content.addView(sv,new LinearLayout.LayoutParams(-1,0,1));}
