 View resCard(Res r){LinearLayout p=panel(); p.setBackground(bg(Color.WHITE,r.tables.isEmpty()?ORANGE:(special(r.notes)?RED:LINE),1,16)); p.addView(txt(r.time+"  "+safe(r.name,"Gast"),21,INK,true)); p.addView(txt(r.party+" personen - "+r.zone+" - "+r.status,15,statusColor(r.status),true)); p.addView(txt("Tafel: "+(r.tables.isEmpty()?"nog geen tafel":names(r.tables)),16,r.tables.isEmpty()?ORANGE:BLUE,true)); if(!r.phone.isEmpty()||!r.email.isEmpty())p.addView(txt(r.phone+"  "+r.email,14,MUTED,false)); if(special(r.notes))p.addView(txt("Speciale wens/allergie: "+r.notes,16,RED,true)); else if(!r.notes.isEmpty())p.addView(txt("Notitie: "+r.notes,15,BLUE,true)); Advice a=dayAdvice(r.time,r.party,r.zone,r.notes); p.addView(riskView(a)); LinearLayout row=row(); Button edit=btn("Wijzig",Color.WHITE,BLACK); edit.setOnClickListener(v->resDialog(r,false)); Button choose=btn("Tafel kiezen",BLUE,Color.WHITE); choose.setOnClickListener(v->chooseTable(r,true)); row.addView(edit,w()); row.addView(choose,w()); p.addView(row); return p;}
